'use client';
import { useState, useEffect } from 'react';
import Link from 'next/link';

interface Attempt {
    id: string;
    score: number;
    createdAt: string;
}

interface Test {
    id: string;
    title: string;
    questionCount: number;
    createdAt: string;
    showResults: boolean;
    attempt: Attempt | null;
}

export default function StudentDashboard() {
    const [name, setName] = useState('');
    const [isAuthenticated, setIsAuthenticated] = useState(false);
    const [tests, setTests] = useState<Test[]>([]);
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        const storedName = localStorage.getItem('studentName');
        if (storedName) {
            setName(storedName);
            setIsAuthenticated(true);
            fetchDashboard(storedName);
        }
    }, []);

    const fetchDashboard = async (studentName: string) => {
        setLoading(true);
        try {
            const res = await fetch(`/api/student/dashboard?name=${encodeURIComponent(studentName)}`);
            const data = await res.json();
            if (res.ok) {
                setTests(data.tests);
            }
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const handleLogin = (e: React.FormEvent) => {
        e.preventDefault();
        if (!name.trim()) return;
        localStorage.setItem('studentName', name);
        setIsAuthenticated(true);
        fetchDashboard(name);
    };

    const handleLogout = () => {
        localStorage.removeItem('studentName');
        setIsAuthenticated(false);
        setName('');
        setTests([]);
    };

    if (!isAuthenticated) {
        return (
            <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4">
                <div className="max-w-md w-full bg-slate-900 border border-slate-800 rounded-2xl p-8 shadow-2xl">
                    <h1 className="text-3xl font-bold text-white text-center mb-2">Welcome</h1>
                    <p className="text-slate-400 text-center mb-8">Enter your name to access tests</p>
                    <form onSubmit={handleLogin} className="space-y-6">
                        <input
                            type="text"
                            required
                            className="w-full bg-slate-950 border border-slate-700 rounded-lg p-4 text-white focus:outline-none focus:border-cyan-500 transition-colors"
                            placeholder="Full Name"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                        />
                        <button
                            type="submit"
                            className="w-full py-4 bg-gradient-to-r from-cyan-600 to-blue-600 rounded-lg text-white font-bold hover:shadow-lg hover:shadow-cyan-500/20 transition-all"
                        >
                            Continue
                        </button>
                    </form>
                </div>
            </div>
        );
    }

    return (
        <div className="min-h-screen bg-slate-950 text-white p-8">
            <div className="max-w-4xl mx-auto">
                <div className="flex justify-between items-center mb-10">
                    <div>
                        <h1 className="text-3xl font-bold text-cyan-400">Student Portal</h1>
                        <p className="text-slate-400">Welcome, {name}</p>
                    </div>
                    <button
                        onClick={handleLogout}
                        className="text-sm text-slate-500 hover:text-white transition-colors"
                    >
                        Logout
                    </button>
                </div>

                {loading ? (
                    <div className="text-center py-20 text-slate-500 animate-pulse">Loading assessments...</div>
                ) : tests.length === 0 ? (
                    <div className="text-center py-20 border border-dashed border-slate-800 rounded-2xl">
                        <p className="text-slate-500">No active tests available at the moment.</p>
                    </div>
                ) : (
                    <div className="space-y-4">
                        {tests.map((test) => (
                            <div key={test.id} className="bg-slate-900 border border-slate-800 rounded-xl p-6 flex flex-col md:flex-row items-center justify-between gap-4 hover:border-slate-700 transition-all">
                                <div>
                                    <h3 className="text-xl font-bold mb-1">{test.title}</h3>
                                    <div className="flex gap-4 text-sm text-slate-400">
                                        <span>{test.questionCount} Questions</span>
                                        <span>•</span>
                                        <span>{new Date(test.createdAt).toLocaleDateString()}</span>
                                    </div>
                                </div>

                                <div>
                                    {test.attempt ? (
                                        <div className="text-right">
                                            <div className="inline-block px-4 py-2 rounded-lg bg-slate-800 text-slate-300 font-medium">
                                                Submitted
                                            </div>
                                            {test.showResults ? (
                                                <div className="mt-2">
                                                    <div className="text-cyan-400 font-bold mb-1">Score: {test.attempt.score}</div>
                                                    <Link href={`/student/results/${test.id}`} className="text-sm text-slate-400 hover:text-white underline decoration-slate-600 underline-offset-4">
                                                        View Analysis
                                                    </Link>
                                                </div>
                                            ) : (
                                                <div className="mt-2 text-slate-500 text-sm italic">Results pending</div>
                                            )}
                                        </div>
                                    ) : (
                                        <Link
                                            href={`/student/test/${test.id}`}
                                            className="inline-block px-8 py-3 bg-cyan-600 hover:bg-cyan-500 text-white font-bold rounded-lg shadow-lg shadow-cyan-500/20 transition-all"
                                        >
                                            Start Test
                                        </Link>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
}
